const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find car stereo category
const stereoCategory = categories.find(c => c.code === 'car_stereos_receivers');
let cheapest = null;
if (stereoCategory) {
  const candidates = products.filter(p => (
    p.categoryId === stereoCategory.id &&
    p.isActive !== false &&
    p.dinSize === 'double_din' &&
    !!p.hasAppleCarPlay &&
    (p.price || 0) < 400 &&
    (p.ratingAverage || 0) >= 4
  ));
  if (candidates.length > 0) {
    cheapest = candidates.reduce((min, p) => (min == null || (p.price || 0) < (min.price || 0)) ? p : min, null);
  }
}

const openCart = carts.find(c => c.status === 'open') || null;
let hasCheapestInCart = false;
if (openCart && cheapest) {
  hasCheapestInCart = cartItems.some(ci => ci.cartId === openCart.id && ci.productId === cheapest.id && ci.quantity > 0);
}

// Single checkpoint: user added the correct cheapest qualifying stereo
checkpoints.push({ passed: !!cheapest && hasCheapestInCart, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const compareSessions = JSON.parse(localStorage.getItem('compare_sessions') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');

const speakersCategory = categories.find(c => c.code === 'speakers');
let qualifyingSpeakers = [];
if (speakersCategory) {
  qualifyingSpeakers = products.filter(p => (
    p.categoryId === speakersCategory.id &&
    p.productType === 'speaker_set' &&
    p.isActive !== false &&
    p.speakerSizeInches === 6.5 &&
    p.speakerType === 'component' &&
    (p.price || 0) >= 100 &&
    (p.price || 0) <= 200 &&
    (p.ratingAverage || 0) >= 4.5
  ));
}

let hasSessionWithTwoQualifying = false;
let higherRmsProductId = null;

for (const session of compareSessions) {
  if (!session || !Array.isArray(session.productIds)) continue;
  const qualifyingIdsInSession = session.productIds.filter(pid => qualifyingSpeakers.some(p => p.id === pid));
  if (qualifyingIdsInSession.length >= 2) {
    const firstTwoIds = qualifyingIdsInSession.slice(0, 2);
    const prodA = qualifyingSpeakers.find(p => p.id === firstTwoIds[0]);
    const prodB = qualifyingSpeakers.find(p => p.id === firstTwoIds[1]);
    if (!prodA || !prodB) continue;
    const rmsA = prodA.rmsPower || 0;
    const rmsB = prodB.rmsPower || 0;
    higherRmsProductId = rmsA >= rmsB ? prodA.id : prodB.id;
    hasSessionWithTwoQualifying = true;
    break;
  }
}

let hasCorrectWishlistItem = false;
if (hasSessionWithTwoQualifying && higherRmsProductId) {
  hasCorrectWishlistItem = wishlistItems.some(wi => wi.productId === higherRmsProductId);
}

// CP1 (0.4): User compared at least two qualifying speakers in a session.
checkpoints.push({ passed: hasSessionWithTwoQualifying, weight: 0.4 });
// CP2 (0.6): User wishlisted the higher-RMS speaker among the compared qualifying pair.
checkpoints.push({ passed: hasSessionWithTwoQualifying && hasCorrectWishlistItem, weight: 0.6 });

return checkoints = checkpoints, checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

function findCheapestQualifying(categoryCode) {
  const cat = categories.find(c => c.code === categoryCode);
  if (!cat) return null;
  const candidates = products.filter(p => (
    p.categoryId === cat.id &&
    p.isActive !== false &&
    (p.ratingAverage || 0) >= 4
  ));
  if (!candidates.length) return null;
  return candidates.reduce((min, p) => (min == null || (p.price || 0) < (min.price || 0)) ? p : min, null);
}

const cheapestStereo = findCheapestQualifying('car_stereos_receivers');
const cheapestSpeaker = findCheapestQualifying('speakers');
const cheapestSub = findCheapestQualifying('subwoofers');

const openCart = carts.find(c => c.status === 'open') || null;
let itemsForCart = [];
if (openCart) {
  itemsForCart = cartItems.filter(ci => ci.cartId === openCart.id && ci.quantity > 0);
}

const hasStereo = !!(cheapestStereo && itemsForCart.some(ci => ci.productId === cheapestStereo.id));
const hasSpeaker = !!(cheapestSpeaker && itemsForCart.some(ci => ci.productId === cheapestSpeaker.id));
const hasSub = !!(cheapestSub && itemsForCart.some(ci => ci.productId === cheapestSub.id));

let combinedUnder600 = false;
if (cheapestStereo && cheapestSpeaker && cheapestSub) {
  const subtotalTargets = (cheapestStereo.price || 0) + (cheapestSpeaker.price || 0) + (cheapestSub.price || 0);
  combinedUnder600 = subtotalTargets < 600;
}

// CP1 (0.25): Cheapest qualifying stereo is in cart.
checkpoints.push({ passed: hasStereo, weight: 0.25 });
// CP2 (0.25): Cheapest qualifying speaker set is in cart.
checkpoints.push({ passed: hasSpeaker, weight: 0.25 });
// CP3 (0.25): Cheapest qualifying subwoofer is in cart.
checkpoints.push({ passed: hasSub, weight: 0.25 });
// CP4 (0.25): Combined prices of those three specific cheapest items are under $600.
checkpoints.push({ passed: hasStereo && hasSpeaker && hasSub && combinedUnder600, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const ampCategory = categories.find(c => c.code === 'amplifiers');
let candidates = [];
if (ampCategory) {
  candidates = products.filter(p => (
    p.categoryId === ampCategory.id &&
    p.productType === 'amplifier' &&
    p.isActive !== false &&
    (p.channelCount || 0) === 4 &&
    (p.rmsPower || 0) >= 600 &&
    (p.price || 0) < 350 &&
    (p.ratingAverage || 0) >= 4
  ));
}

let bestCandidates = [];
if (candidates.length > 0) {
  const maxReviews = candidates.reduce((max, p) => Math.max(max, p.ratingCount || 0), 0);
  bestCandidates = candidates.filter(p => (p.ratingCount || 0) === maxReviews);
}

const openCart = carts.find(c => c.status === 'open') || null;
let itemsForCart = [];
if (openCart) {
  itemsForCart = cartItems.filter(ci => ci.cartId === openCart.id && ci.quantity > 0);
}

const candidateInCart = itemsForCart.some(ci => candidates.some(p => p.id === ci.productId));
const bestCandidateInCart = itemsForCart.some(ci => bestCandidates.some(p => p.id === ci.productId));

// CP1 (0.4): User added a qualifying 4-channel 600W+ amp under $350 with rating ≥4.
checkpoints.push({ passed: candidateInCart, weight: 0.4 });
// CP2 (0.6): The added amp is among the most-reviewed qualifying options.
checkpoints.push({ passed: candidateInCart && bestCandidateInCart, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const candidates = products.filter(p => (
  p.productType === 'bundle' &&
  p.isBundle === true &&
  p.bundleType === 'subwoofer_amplifier_bundle' &&
  !!p.includesWiringKit &&
  !!p.freeShippingEligible &&
  (p.price || 0) >= 250 &&
  (p.price || 0) <= 450 &&
  p.isActive !== false
));

const openCart = carts.find(c => c.status === 'open') || null;
let itemsForCart = [];
if (openCart) {
  itemsForCart = cartItems.filter(ci => ci.cartId === openCart.id && ci.quantity > 0);
}

const hasBundleAnyQty = itemsForCart.some(ci => candidates.some(p => p.id === ci.productId));
const hasBundleQty2 = itemsForCart.some(ci => candidates.some(p => p.id === ci.productId) && ci.quantity >= 2);

// CP1 (0.4): User added a qualifying sub+amp bundle meeting all feature and price criteria.
checkpoints.push({ passed: hasBundleAnyQty, weight: 0.4 });
// CP2 (0.6): The qualifying bundle is present with quantity at least 2.
