const checkpoints = [];

const vehicles = JSON.parse(localStorage.getItem('vehicles') || '[]');
const selectedVehicles = JSON.parse(localStorage.getItem('selected_vehicles') || '[]');
const fitments = JSON.parse(localStorage.getItem('vehicle_product_fitments') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const civic = vehicles.find(v => v.displayName === '2018 Honda Civic Sedan');
let hasSelectedCivic = false;
if (civic && selectedVehicles.length > 0) {
  hasSelectedCivic = selectedVehicles[0].vehicleId === civic.id;
}

// Gather fit-compatible product IDs (exact or partial fit) for Civic
let fitProductIds = new Set();
if (civic) {
  fitments.forEach(f => {
    if (f.vehicleId === civic.id && (f.fitmentType === 'exact_fit' || f.fitmentType === 'partial_fit')) {
      fitProductIds.add(f.productId);
    }
  });
}

const stereoCategory = categories.find(c => c.code === 'car_stereos_receivers');
let qualifying = [];
if (stereoCategory && civic) {
  qualifying = products.filter(p => (
    p.categoryId === stereoCategory.id &&
    p.isActive !== false &&
    !!p.hasBluetooth &&
    !!p.hasBackupCameraInput &&
    (p.price || 0) < 500 &&
    (p.ratingAverage || 0) >= 4 &&
    fitProductIds.has(p.id)
  ));
}

let secondCheapest = null;
if (qualifying.length >= 2) {
  const sorted = qualifying.slice().sort((a, b) => (a.price || 0) - (b.price || 0));
  secondCheapest = sorted[1];
}

const openCart = carts.find(c => c.status === 'open') || null;
let itemsForCart = [];
if (openCart) {
  itemsForCart = cartItems.filter(ci => ci.cartId === openCart.id && ci.quantity > 0);
}

const anyQualifyingInCart = itemsForCart.some(ci => qualifying.some(p => p.id === ci.productId));
const hasSecondCheapestInCart = !!(secondCheapest && itemsForCart.some(ci => ci.productId === secondCheapest.id));

// CP1 (0.3): User selected 2018 Honda Civic Sedan as the current vehicle.
checkpoints.push({ passed: !!civic && hasSelectedCivic, weight: 0.3 });
// CP2 (0.4): User added some stereo that fits the Civic and meets all feature/price/rating criteria.
checkpoints.push({ passed: anyQualifyingInCart, weight: 0.4 });
// CP3 (0.3): The stereo in the cart is the second-cheapest among those qualifying options.
checkpoints.push({ passed: anyQualifyingInCart && hasSecondCheapestInCart, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const protectionPlans = JSON.parse(localStorage.getItem('protection_plans') || '[]');
const shippingMethods = JSON.parse(localStorage.getItem('shipping_methods') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const sessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');

// Find most recent completed checkout session
const completedSessions = sessions.filter(s => s.status === 'completed');
let completedSession = null;
if (completedSessions.length > 0) {
  completedSession = completedSessions.slice().sort((a, b) => {
    const ta = new Date(a.updatedAt || a.createdAt || 0).getTime();
    const tb = new Date(b.updatedAt || b.createdAt || 0).getTime();
    return tb - ta;
  })[0];
}

let targetCart = null;
let itemsForCart = [];
if (completedSession) {
  targetCart = carts.find(c => c.id === completedSession.cartId) || null;
  if (targetCart) {
    itemsForCart = cartItems.filter(ci => ci.cartId === targetCart.id && ci.quantity > 0);
  }
}

const stereoCategory = categories.find(c => c.code === 'car_stereos_receivers');
let premiumStereos = [];
if (stereoCategory) {
  premiumStereos = products.filter(p => (
    p.categoryId === stereoCategory.id &&
    p.productType === 'car_stereo' &&
    p.isActive !== false &&
    (p.price || 0) > 700 &&
    (p.ratingAverage || 0) >= 4.5
  ));
}

let purchasedItem = null;
let purchasedStereo = null;
if (completedSession && targetCart) {
  purchasedItem = itemsForCart.find(ci => premiumStereos.some(p => p.id === ci.productId));
  if (purchasedItem) {
    purchasedStereo = premiumStereos.find(p => p.id === purchasedItem.productId) || null;
  }
}

// Find any 3-year protection plans applicable to car stereos
const threeYearPlans = protectionPlans.filter(pl => (
  pl.status === 'active' &&
  pl.durationYears === 3 &&
  (pl.applicableProductType === 'car_stereo' || pl.applicableProductType === 'any_product_type')
));

let hasThreeYearPlan = false;
if (purchasedItem && purchasedItem.protectionPlanId) {
  hasThreeYearPlan = threeYearPlans.some(pl => pl.id === purchasedItem.protectionPlanId);
}

let hasStandardShipping = false;
if (completedSession && completedSession.shippingMethodId) {
  const method = shippingMethods.find(m => m.id === completedSession.shippingMethodId);
  hasStandardShipping = !!(method && method.code === 'standard');
}

let hasCorrectContact = false;
if (completedSession) {
  hasCorrectContact = completedSession.contactEmail === 'user@example.com' && completedSession.contactFullName === 'Test User';
}

// CP1 (0.25): Completed checkout includes a qualifying premium stereo in the order.
checkpoints.push({ passed: !!(completedSession && targetCart && purchasedStereo), weight: 0.25 });
// CP2 (0.25): That stereo line has an attached 3-year applicable protection plan.
checkpoints.push({ passed: !!(completedSession && targetCart && purchasedStereo && hasThreeYearPlan), weight: 0.25 });
// CP3 (0.25): Checkout used Standard Shipping.
checkpoints.push({ passed: !!(completedSession && hasStandardShipping), weight: 0.25 });
// CP4 (0.25): Checkout contact email and full name match the specified values.
checkpoints.push({ passed: !!(completedSession && hasCorrectContact), weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const installCat = categories.find(c => c.code === 'installation_accessories');
let wiringCandidates = [];
let dashCandidates = [];
let antennaCandidates = [];

if (installCat) {
  const base = products.filter(p => (
    p.categoryId === installCat.id &&
    p.productType === 'installation_accessory' &&
    p.isActive !== false &&
    (p.price || 0) < 40 &&
    (p.ratingAverage || 0) >= 4
  ));
  wiringCandidates = base.filter(p => p.accessoryType === 'amp_wiring_kit');
  dashCandidates = base.filter(p => p.accessoryType === 'dash_kit');
  antennaCandidates = base.filter(p => p.accessoryType === 'antenna_adapter');
}

const openCart = carts.find(c => c.status === 'open') || null;
let itemsForCart = [];
if (openCart) {
  itemsForCart = cartItems.filter(ci => ci.cartId === openCart.id && ci.quantity > 0);
}

const hasWiring = itemsForCart.some(ci => wiringCandidates.some(p => p.id === ci.productId));
const hasDash = itemsForCart.some(ci => dashCandidates.some(p => p.id === ci.productId));
const hasAntenna = itemsForCart.some(ci => antennaCandidates.some(p => p.id === ci.productId));

// CP1 (0.33): A qualifying amp wiring kit is in the cart.
checkpoints.push({ passed: hasWiring, weight: 0.33 });
// CP2 (0.33): A qualifying dash kit is in the cart.
checkpoints.push({ passed: hasDash, weight: 0.33 });
// CP3 (0.34): A qualifying antenna adapter is in the cart.
checkpoints.push({ passed: hasAntenna, weight: 0.34 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
